import { useState } from 'react';
import { api, apiPost } from '../utils/api';
import { useToast } from '../components/ui/Toast';

const BADGE_COLORS = { gold: '#D29922', silver: '#8B949E', bronze: '#CD7F32' };

export default function ShareCard({ card, onClose }) {
  const toast = useToast();
  if (!card) return null;

  const shareText = `I'm ranked #${card.rank} on Aura Alpha! ${card.cumulative_return > 0 ? '+' : ''}${card.cumulative_return?.toFixed(1)}% return, ${card.streak}d streak. Compete with me: ${card.share_url || 'auraalpha.cc'}`;

  const handleShare = async (platform) => {
    try { await apiPost('/growth/share', { share_type: 'card', platform }); } catch {}

    if (platform === 'twitter') {
      window.open(`https://x.com/intent/tweet?text=${encodeURIComponent(shareText)}`, '_blank');
    } else if (platform === 'copy') {
      navigator.clipboard.writeText(shareText);
      toast.success('Copied!', 'Share link copied to clipboard');
    } else if (platform === 'discord') {
      navigator.clipboard.writeText(shareText);
      toast.success('Copied for Discord!', 'Paste it in your Discord server');
    }
  };

  return (
    <div style={{ position: 'fixed', inset: 0, zIndex: 9999, background: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(4px)', display: 'flex', alignItems: 'center', justifyContent: 'center' }} onClick={onClose}>
      <div onClick={e => e.stopPropagation()} style={{ background: 'linear-gradient(135deg, #161B22, #1C2128)', border: '1px solid #30363D', borderRadius: 16, padding: 28, maxWidth: 380, width: '90%' }}>
        {/* Card */}
        <div style={{ textAlign: 'center', marginBottom: 20 }}>
          <div style={{ fontSize: 12, color: '#8B949E', letterSpacing: 1, textTransform: 'uppercase', marginBottom: 8 }}>Aura Alpha</div>
          <div style={{ fontSize: 22, fontWeight: 700, color: '#E6EDF3', marginBottom: 4 }}>{card.alias}</div>
          {card.badge && (
            <span style={{ fontSize: 11, padding: '2px 8px', borderRadius: 8, background: (BADGE_COLORS[card.badge] || '#8B949E') + '22', color: BADGE_COLORS[card.badge] || '#8B949E', fontWeight: 700 }}>
              {card.badge.toUpperCase()}
            </span>
          )}
        </div>

        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, marginBottom: 20 }}>
          {[
            { label: 'Rank', value: `#${card.rank}`, color: '#58A6FF' },
            { label: 'Return', value: `${card.cumulative_return > 0 ? '+' : ''}${card.cumulative_return?.toFixed(1)}%`, color: card.cumulative_return > 0 ? '#3FB950' : '#F85149' },
            { label: 'Win Rate', value: `${card.win_rate?.toFixed(0)}%`, color: '#E6EDF3' },
            { label: 'Streak', value: `${card.streak}d`, color: card.streak >= 7 ? '#D29922' : '#E6EDF3' },
            { label: 'XP', value: card.xp?.toLocaleString(), color: '#BC8CFF' },
            { label: 'Tier', value: card.tier?.charAt(0).toUpperCase() + card.tier?.slice(1), color: '#58A6FF' },
          ].map(m => (
            <div key={m.label} style={{ background: '#0D1117', borderRadius: 8, padding: '8px 12px', textAlign: 'center' }}>
              <div style={{ fontSize: 10, color: '#8B949E', textTransform: 'uppercase', letterSpacing: 0.5 }}>{m.label}</div>
              <div style={{ fontSize: 16, fontWeight: 700, color: m.color, fontFamily: "'JetBrains Mono', monospace" }}>{m.value}</div>
            </div>
          ))}
        </div>

        {/* Share buttons */}
        <div style={{ display: 'flex', gap: 8 }}>
          <button onClick={() => handleShare('twitter')} style={{ flex: 1, padding: 10, borderRadius: 8, border: 'none', background: '#1DA1F222', color: '#1DA1F2', fontWeight: 600, fontSize: 13, cursor: 'pointer' }}>
            Share on X
          </button>
          <button onClick={() => handleShare('discord')} style={{ flex: 1, padding: 10, borderRadius: 8, border: 'none', background: '#5865F222', color: '#5865F2', fontWeight: 600, fontSize: 13, cursor: 'pointer' }}>
            Discord
          </button>
          <button onClick={() => handleShare('copy')} style={{ flex: 1, padding: 10, borderRadius: 8, border: 'none', background: '#30363D', color: '#E6EDF3', fontWeight: 600, fontSize: 13, cursor: 'pointer' }}>
            Copy Link
          </button>
        </div>
      </div>
    </div>
  );
}
